let dotNetRef = null;
let timeoutMs = 0;
let timerId = null;
let isIdle = false;

const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];

function onActivity() {
    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync("OnActiveCallback");
    }
    resetTimer();
}

function resetTimer() {
    if (timerId !== null) {
        clearTimeout(timerId);
    }
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);
}

export function initialize(ref, timeout) {
    dotNetRef = ref;
    timeoutMs = timeout;
    isIdle = false;

    for (const evt of events) {
        document.addEventListener(evt, onActivity, { passive: true });
    }
    resetTimer();
}

export function dispose() {
    if (timerId !== null) {
        clearTimeout(timerId);
        timerId = null;
    }
    for (const evt of events) {
        document.removeEventListener(evt, onActivity);
    }
    dotNetRef = null;
    isIdle = false;
}

